function [pvtXInd,pvtYInd,rotAngl,img] = fImgCntAnglV05(img,angle,osPrp,rawFrgT,rawFrgL,varargin)%% analyze image to get centroid and rotation angle% [pvtXInd,pvtYInd,rotAngl] = fImgCntAnglV04(img,angle,varargin)% cntX, cntY: centroid [pixel]% rotAngl: rotation angle [deg]% % img: input image% threshold: threshold% vergin: if any, output figure, %       {1}: rawFrgT%       {2}: rawFrgL%% Written by Kei Nakamura% 2016/1/6 ver.1: created% 2016/1/7 ver.2: output centroid and angle% 2016/1/25 ver.3: improve% 2016/1/27 ver.4: angle scan or no scan% 2016/5/12 ver.5: it wasn't simple rotation%%% used in% bellaFrogFirstAnlV04%% inputssmth = 31;  % smoothness parameterpkThre = 0.1;   % peak detection thresholdsmThre = 0.3;   % sum threshold %% common processingrawImg = img;   % raw image[img(:,:),~] = fXrayOutV10(img,[1/4,3,1,2]);    % low pass[img(:,:),~] = fXrayOutV10(img,[1/4,2,1,2]);[img(:,:),~] = fXrayOutV10(img,[1/4,1,1,2]);[sizeY,sizeX] = size(img);  % image sizeyPixl = 1:sizeY;[~,pvtYInd] = min(abs(rawFrgL - 0.5*osPrp.lmb0));   % pivot y pixelcntWvl = 0.5*osPrp.lmb0;%% if numel(angle)>1   % angle scan     %% find out angle        % allocation    line1 = 1:sizeX; line2 = line1; line3 = line1;     pvtXIndAry = 1:sizeY; sumX = pvtXIndAry;    % get central pixel for each row    for ii=1:sizeY        line1(:) = img(ii,:)/max(img(ii,:));        line1(:) = fSmoothAryV01(line1,smth);        line2(:) = [fSmoothAryV01(diff(line1),smth),0];  % padded         line2(:) = line2/max(line2);        line3(:) = [sign(line2(1:end-1)).*sign(line2(2:end)),0];        peakInd = find(line3==-1&line1>pkThre);        pvtXIndAry(ii) = mean(peakInd);        sumX(ii) = sum(img(ii,:));    end    sumX(:) = sumX/max(sumX);    dataP = sumX>smThre;    lineX = yPixl(dataP); lineY = pvtXIndAry(dataP);    meanY = mean(lineY);    dataS = abs(lineY - meanY)<std(lineY);    poly1 = polyfit(lineX(dataS),lineY(dataS),1);    pvtXInd = round(polyval(poly1,pvtYInd));    % pivot x index    anglD = 180*atan(-1/poly1(1))/pi;    if sign(anglD)==1        rotAngl = 90 - anglD;  % rotation angle [deg]    else        rotAngl = - 90 - anglD;  % rotation angle [deg]    end    % lines    pvtT = rawFrgT(pvtXInd);  % pivot time    a2 = -tan((90-rotAngl)*pi/180);    a2C = a2 * (rawFrgL(2) - rawFrgL(1)) / (rawFrgT(2) - rawFrgT(1));   % slope in fs-nm    lin2 = fPa2Line([pvtT cntWvl],a2C);        %% test% figure(100)% pcolor(img)% shading interp% hold on% plot(pvtXInd(dataP),yPixl(dataP),'w-')% plot(polyval(poly1,yPixl),yPixl,'k-')% hold off% disp([yPixl(dataP);pvtXInd(dataP)]')% pvtYInd = 395;% line1 = img(pvtYInd,:)/max(img(pvtYInd,:));% line1 = fSmoothAryV01(line1,smth);% line2 = [fSmoothAryV01(diff(line1),smth),0];  % padded % line2 = line2/max(abs(line2));% line3 = [sign(line2(1:end-1)).*sign(line2(2:end)),0];% line4 = [diff(line2),0];% line4 = line4/max(abs(line4));% peakInd = find(line3==-1&line1>0.1);% pvtXInd = mean(peakInd);% figure(101)% plotyy(yPixl(dataP),pvtXInd(dataP),yPixl,sumX)% hold on% hold off% figure(102)% plot(lineX(dataS),lineY(dataS),'ro')% hold on% plot(yPixl,polyval(poly1,yPixl),'k-')% hold off% figure(103)% plot(line1)% hold on% plot(line2)% plot(line3)% plot(line4)% hold off    %% figure output    set(gca,'fontsize',14);    pcolor(rawFrgT,rawFrgL,rawImg)    shading interp    colormap jet    hold on    plot([-200 200],[cntWvl cntWvl],'k-')    plot([-200 200],[404.5 404.5],'k--')    plot([-200 200],[400 400],'k--')    plot([-200 200],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w-')    plot([-300 100],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w--')    plot([-100 300],[fLineX2YV01(lin2,-200) fLineX2YV01(lin2,200)],'w--')    hold off    axis([-150 150 385 415])    cax = caxis;    caxis([-0.1*cax(2) 0.9*cax(2)])    set(gca,'fontsize',14);    elseif nargin==5 % static angle, find out time shift          % findout pvt x    rotAngl = angle;    line1 = img(pvtYInd,:)/max(img(pvtYInd,:));    line1 = fSmoothAryV01(line1,smth);    line2 = [fSmoothAryV01(diff(line1),smth),0];  % padded     line2 = line2/max(abs(line2));    line3 = [sign(line2(1:end-1)).*sign(line2(2:end)),0];    peakInd = find(line3==-1&line1>0.1);    pvtXInd = round(mean(peakInd));    % rotate (slide) image    img = fFrogSCSlideV01(rawImg,[pvtXInd,pvtYInd],angle);    % for plot    pvtT = rawFrgT(pvtXInd);  % pivot time        %% previous way get pvt x  %     xPrf = sum(img);    % integrate in y%     for ii = 101:0.5*sizeX-1%         rght = xPrf(ii+1:ii+0.5*sizeX); % right side%         left = [fliplr(rght(ii+1:end)) xPrf(1:ii)];  % left side%         rght = rght + fliplr(left); % symmetrize%         rmsT(ii-100) = fGetRmsV01(1:0.5*sizeX,rght);    % rms of symmetrized profile%     end%     temp = xPrf + fliplr(xPrf); % symmetrize%     rmsM = fGetRmsV01(1:0.5*sizeX,temp(1:0.5*sizeX));%     xPrf = fliplr(xPrf);    % flip for other side%     for ii = 101:0.5*sizeX-1%         rght = xPrf(ii+1:ii+0.5*sizeX); % right side%         left = [fliplr(rght(ii+1:end)) xPrf(1:ii)];  % left side%         rght = rght + fliplr(left); % symmetrize%         rmsT2(ii-100) = fGetRmsV01(1:0.5*sizeX,rght);    % rms of symmetrized profile%     end%     rmsAll = [rmsT rmsM fliplr(rmsT2)];%     [~,minIdx] = min(rmsAll);%     pvtXInd2 = minIdx + 100;%     pvtYInd = pvtXInd2;%     rotAngl = angle;%     pvtT = interp1(1:sizeX,rawFrgT,pvtXInd2);        %% test%     figure(100)%     subplot(1,3,1)%     plot(xShiftAry)%     subplot(1,3,2)%     pcolor(rawImg)%     shading interp%     subplot(1,3,3)%     pcolor(sldImg)%     shading interp%     figure(200)        %% figure output    set(gca,'fontsize',14);    pcolor(rawFrgT,rawFrgL,img)    shading interp    colormap jet    hold on    plot([pvtT pvtT],[0 800],'w-')%     plot([pvtT+50 pvtT+50],[0 800],'w--')%     plot([pvtT-50 pvtT-50],[0 800],'w--')    plot([pvtT+100 pvtT+100],[0 800],'w--')    plot([pvtT-100 pvtT-100],[0 800],'w--')    plot([-200 200],[0.5*osPrp.lmb0 0.5*osPrp.lmb0],'k-')%     plot([-200 200],[0.5*osPrp.lmb0+3 0.5*osPrp.lmb0+3],'k--')%     plot([-200 200],[0.5*osPrp.lmb0-3 0.5*osPrp.lmb0-3],'k--')    plot([-200 200],[404 404],'k--')    plot([-200 200],[399 399],'k--')    hold off    %axis([-100 200 385 415])    axis([-150 150 385 415])    set(gca,'fontsize',14);else % static angle and offset case        rotAngl = angle;    pvtT = varargin{1};    % pivot [fs]    [~,pvtXInd] = min(abs(rawFrgT - pvtT));   % pivot x pixel        % rotate (slide) image    img = fFrogSCSlideV01(rawImg,[pvtXInd,pvtYInd],angle);        %% figure output    set(gca,'fontsize',14);    pcolor(rawFrgT,rawFrgL,img)    shading interp    colormap jet    hold on    plot([pvtT pvtT],[0 800],'w-')%     plot([pvtT+40 pvtT+40],[0 800],'w--')%     plot([pvtT-40 pvtT-40],[0 800],'w--')    plot([pvtT+80 pvtT+80],[0 800],'w--')    plot([pvtT-80 pvtT-80],[0 800],'w--')    plot([-200 200],[0.5*osPrp.lmb0 0.5*osPrp.lmb0],'k-')%     plot([-200 200],[0.5*osPrp.lmb0+3 0.5*osPrp.lmb0+3],'k--')%     plot([-200 200],[0.5*osPrp.lmb0-3 0.5*osPrp.lmb0-3],'k--')    plot([-200 200],[404 404],'k--')    plot([-200 200],[399 399],'k--')    hold off    axis([-150 150 385 415])    set(gca,'fontsize',14);end
